import{_ as i,c as t,o as l,Q as c}from"./chunks/framework.c6e9ece7.js";const o="/git1.png",b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"post/note/tools.md","lastUpdated":1681747002000}'),e={name:"post/note/tools.md"},d=c('<h2 id="_1-git" tabindex="-1">1. Git <a class="header-anchor" href="#_1-git" aria-label="Permalink to &quot;1. Git&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">git 日常基本操作</p><ul><li><code>git init</code>初始化仓库，默认为 master 分支</li><li><code>git add .</code>提交全部文件修改到缓存区</li><li><code>git add &lt;具体某个文件路径+全名&gt;</code>提交某些文件到缓存区</li><li><code>git diff</code>查看当前代码 add后，会 add 哪些内容</li><li><code>git diff --staged</code>查看现在 commit 提交后，会提交哪些内容</li><li><code>git status</code>查看当前分支状态</li><li><code>git pull &lt;远程仓库名&gt; &lt;远程分支名&gt;</code>拉取远程仓库的分支与本地当前分支合并</li><li><code>git pull &lt;远程仓库名&gt; &lt;远程分支名&gt;:&lt;本地分支名&gt;</code>拉取远程仓库的分支与本地某个分支合并</li><li><code>git commit -m &quot;&lt;注释&gt;&quot;</code>提交代码到本地仓库，并写提交注释</li><li><code>git commit -v</code>提交时显示所有diff信息</li><li><code>git commit --amend [file1] [file2]</code>重做上一次commit，并包括指定文件的新变化</li></ul></div><div class="tip custom-block"><p class="custom-block-title">关于提交信息的格式，可以遵循以下的规则</p><ul><li><code>feat</code>新特性，添加功能</li><li><code>fix</code>修改 bug</li><li><code>refactor</code>代码重构</li><li><code>docs</code>文档修改</li><li><code>style</code>代码格式修改, 注意不是 css 修改</li><li><code>test</code>测试用例修改</li><li><code>chore</code>其他修改, 比如构建流程, 依赖管理</li></ul></div><div class="tip custom-block"><p class="custom-block-title">分支操作</p><ul><li><code>git branch</code>查看本地所有分支</li><li><code>git branch -r</code>查看远程所有分支</li><li><code>git branch -a</code>查看本地和远程所有分支</li><li><code>git merge &lt;分支名&gt;</code>合并分支</li><li><code>git merge --abort</code>合并分支出现冲突时，取消合并，一切回到合并前的状态</li><li><code>git branch &lt;新分支名&gt;</code>基于当前分支，新建一个分支</li><li><code>git checkout --orphan &lt;新分支名&gt;</code>新建一个空分支（会保留之前分支的所有文件）</li><li><code>git branch -D &lt;分支名&gt;</code>删除本地某个分支</li><li><code>git push &lt;远程库名&gt; :&lt;分支名&gt;</code>删除远程某个分支</li><li><code>git branch &lt;新分支名称&gt; &lt;提交ID&gt;</code>从提交历史恢复某个删掉的某个分支</li><li><code>git branch -m &lt;原分支名&gt; &lt;新分支名&gt;</code>分支更名</li><li><code>git checkout &lt;分支名&gt;</code>切换到本地某个分支</li><li><code>git checkout &lt;远程库名&gt;/&lt;分支名&gt;</code>切换到线上某个分支 -<code> git checkout -b &lt;新分支名&gt;</code>把基于当前分支新建分支，并切换为这个分支</li></ul></div><div class="tip custom-block"><p class="custom-block-title">远程同步</p><ul><li><code>git fetch [remote]</code>下载远程仓库的所有变动</li><li><code>git remote -v</code>显示所有远程仓库</li><li><code>git pull [remote] [branch]</code>拉取远程仓库的分支与本地当前分支合并</li><li><code>git fetch</code>获取线上最新版信息记录，不合并</li><li><code>git push [remote] [branch]</code>上传本地指定分支到远程仓库</li><li><code>git push [remote] --force</code>强行推送当前分支到远程仓库，即使有冲突</li><li><code>git push [remote] --all</code>推送所有分支到远程仓库</li></ul></div><div class="tip custom-block"><p class="custom-block-title">撤销</p><ul><li><code>git checkout [file]</code>恢复暂存区的指定文件到工作区</li><li><code>git checkout [commit] [file]</code>恢复某个commit的指定文件到暂存区和工作区</li><li><code>git checkout .</code>恢复暂存区的所有文件到工作区</li><li><code>git reset [commit]</code>重置当前分支的指针为指定commit，同时重置暂存区，但工作区不变</li><li><code>git reset --hard</code>重置暂存区与工作区，与上一次commit保持一致</li><li><code>git reset [file]</code>重置暂存区的指定文件，与上一次commit保持一致，但工作区不变</li><li><code>git revert [commit]</code>后者的所有变化都将被前者抵消，并且应用到当前分支</li></ul></div><div class="tip custom-block"><p class="custom-block-title">存储操作</p><ul><li><code>git stash</code>暂时将未提交的变化移除</li><li><code>git stash pop</code>取出储藏中最后存入的工作状态进行恢复，会删除储藏</li><li><code>git stash list</code>查看所有储藏中的工作</li><li><code>git stash apply &lt;储藏的名称&gt;</code>取出储藏中对应的工作状态进行恢复，不会删除储藏</li><li><code>git stash clear</code>清空所有储藏中的工作</li><li><code>git stash drop &lt;储藏的名称&gt;</code>删除对应的某个储藏</li></ul></div><div class="tip custom-block"><p class="custom-block-title">总结</p><p><img src="'+o+'" alt="pic" title="notice"></p></div><h2 id="_2-n" tabindex="-1">2. N <a class="header-anchor" href="#_2-n" aria-label="Permalink to &quot;2. N&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">n</p><ul><li><code>npm install -g n</code>全局安装 n</li><li><code>n</code>查看已安装node列表并切换</li><li><code>n ls</code>查看已安装node列表</li><li><code>n lsr</code>Displaying 20 matches (use --all to see all)</li><li><code>sudo n stable</code>安装稳定版本</li><li><code>sudo n latest</code>安装最新版本</li><li><code>sudo n 8.4.0</code>安装指定版本</li><li><code>sudo n rm 8.4.0</code>删除某个版本</li><li><code>n use 8.4.0 index.js</code>以指定的版本来执行脚本</li></ul></div>',10),s=[d];function a(g,m,r,u,n,p){return l(),t("div",null,s)}const _=i(e,[["render",a]]);export{b as __pageData,_ as default};
